+        b"cl",
+        epoch(),
+    );
+    let cx = evaluate_counterexample(&wl, "claim-5", 1_000_000, 100_000).unwrap();
+    let mut cloned = cx.clone();
+    cloned.explanation = "changed".to_string();
+    assert_ne!(cx.explanation, cloned.explanation);
+}
