+// ===========================================================================
+// 1. ModuleStatus — Copy, Display uniqueness, serde, Debug
+// ===========================================================================
+
+#[test]
+fn enrichment_module_status_copy_semantics() {
+    let a = ModuleStatus::Unlinked;
+    let b = a;
+    let c = a;
+    assert_eq!(b, c);
+    assert_eq!(a, ModuleStatus::Unlinked);
+}
