+fn test_gate_id(suffix: &str) -> EngineObjectId {
+    derive_id(
+        ObjectDomain::EvidenceRecord,
+        suffix,
+        &SchemaId::from_definition(b"frontier-demo-gate-enrich"),
+        b"frontier-demo-gate-enrich",
+    )
